package org.apache.commons.csv;

import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import static org.junit.jupiter.api.Assertions.assertArrayEquals;

public class CSVFormatTest {

    @Test
    public void testGetHeaderComments() throws Exception {
        // Given
        CSVFormat csvFormat = CSVFormat.class.getDeclaredConstructor(char.class, Character.class, QuoteMode.class, Character.class, Character.class, boolean.class, boolean.class, String.class, String.class, Object[].class, String[].class, boolean.class, boolean.class, boolean.class, boolean.class, boolean.class)
                .newInstance(',', '"', null, null, null, false, true, "\r\n",
                        null, null, null, false, false, false, false, false);
        String[] expectedHeaderComments = {"Header comment 1", "Header comment 2"};
        csvFormat.withHeaderComments(expectedHeaderComments);

        // When
        String[] actualHeaderComments = csvFormat.getHeaderComments();

        // Then
        assertArrayEquals(expectedHeaderComments, actualHeaderComments);
    }
}
